"""
Test Suite: Wire Transfer with Two-Factor Authentication and Manual Review
Requirement: A customer shall initiate a wire transfer requiring two-factor
             authentication; transfers above $100,000 require manual review.
"""

import pytest
from unittest.mock import MagicMock, patch, call
from decimal import Decimal
from enum import Enum


# ---------------------------------------------------------------------------
# Domain models / enums assumed to exist in the production code
# ---------------------------------------------------------------------------
class TransferStatus(Enum):
    PENDING_2FA = "pending_2fa"
    PENDING_MANUAL_REVIEW = "pending_manual_review"
    APPROVED = "approved"
    REJECTED = "rejected"
    COMPLETED = "completed"
    FAILED = "failed"


class TwoFactorMethod(Enum):
    SMS = "sms"
    EMAIL = "email"
    TOTP = "totp"


# ---------------------------------------------------------------------------
# Exceptions assumed to exist in the production code
# ---------------------------------------------------------------------------
class TwoFactorAuthRequiredError(Exception):
    """Raised when 2FA has not been completed before initiating a transfer."""


class InvalidTwoFactorCodeError(Exception):
    """Raised when the provided 2FA code is incorrect or expired."""


class ManualReviewRequiredError(Exception):
    """Raised when a transfer is routed for manual review (amount > $100,000)."""


class InsufficientFundsError(Exception):
    """Raised when the account does not have sufficient funds."""


class InvalidTransferAmountError(Exception):
    """Raised for non-positive or otherwise invalid transfer amounts."""


class UnauthorizedCustomerError(Exception):
    """Raised when the customer is not authorized to initiate transfers."""


